let random=async t=>crypto.getRandomValues(new Uint8Array(t)),customAlphabet=(a,t=21)=>{let o=(2<<Math.log(a.length-1)/Math.LN2)-1,l=-~(1.6*o*t/a.length);return async(n=t)=>{let e="";for(;;){var r=crypto.getRandomValues(new Uint8Array(l));let t=l;for(;t--;)if((e+=a[r[t]&o]||"").length===n)return e}}},nanoid=async(n=21)=>{let e="";for(var r=crypto.getRandomValues(new Uint8Array(n));n--;){let t=63&r[n];t<36?e+=t.toString(36):t<62?e+=(t-26).toString(36).toUpperCase():t<63?e+="_":e+="-"}return e};module.exports={nanoid:nanoid,customAlphabet:customAlphabet,random:random};